*�����������������?blendModeNames = ['over', 'average', 'under', 'cross', 'darken', 'lighten', 
			'multiply', 'screen', 'colorBurn', 'colorDodge', 'overlay', 'softLight', 
			'hardLight', 'add', 'subtract', 'difference', 'invDifference', 'exclusion']

blendModeLabels = ['Over', 'Average', 'Under', 'Cross', 'Darken', 'Lighten', 
			'Multiply', 'Screen', 'Col Burn', 'Col Dodge', 'Overlay', 'SoftLight', 
			'HardLight', 'Add', 'Subtract', 'Diff', 'Inv Diff', 'Exclude']

multiMixFrag = {}

multiMixFrag['initDefines'] = '''
#define COLOR texture(sTD2DInputs[i], texCoord)
#define CROP Crop(COLOR, Coord(i), i)
#define BLEND0 blend * uOpacity[i]
'''


multiMixFrag['varDef'] = '''
const vec4 WHITE = vec4(1.0,1.0,1.0,1.0);
const vec4 LUM_COEFF = vec4(0.2125,0.7154,0.0721,1.0);

uniform float uOpacity[LAYERS];
uniform vec2 uTranslate[LAYERS];
uniform vec2 uScale[LAYERS];
uniform vec4 uRotMAT[LAYERS];
uniform vec2 uPivot[LAYERS];
uniform vec4 uPreFit[LAYERS];
uniform vec2 uTexAspect[LAYERS];
uniform vec4 uCrop[LAYERS];

float aspect = uTDOutputInfo.res.w / uTDOutputInfo.res.z;
float invAspect = 1.0 / aspect;
'''


multiMixFrag['coord'] = '''
vec2 Coord(int i){	
	vec2 coord = vUV.st * uPreFit[i].zw + uPreFit[i].xy;
	coord = 2.0 * coord - 1.0; coord.t *= aspect;
	coord.t *= invAspect; coord = .5 * coord + .5;
	return coord;
}
'''

multiMixFrag['coordTransform'] = '''
vec2 Coord(int i){	
	vec2 coord = vUV.st * uPreFit[i].zw + uPreFit[i].xy;
	coord = 2.0 * (coord + uPivot[i]) - 1.0; coord.t *= uTexAspect[i].x; //aspect;
	coord -= uTranslate[i]; coord = mat2(uRotMAT[i]) * coord; coord *= uScale[i];	
	coord.t *= uTexAspect[i].y; coord = .5 * coord + .5 - uPivot[i];
	return coord;
}
'''
multiMixFrag['crop'] = '''
vec4 Crop(vec4 color, vec2 coord, int i){
	int alpha = int(coord.s >= uCrop[i].x) * int(coord.s < uCrop[i].y) * int(coord.t >= uCrop[i].z) * int(coord.t < uCrop[i].w);
	return color * alpha;
}

'''

multiMixFrag['cropOld'] = '''
vec4 Crop(vec4 color, vec2 coord, int i){
	float alpha = 1.0;
	if (coord.s < uCrop[i].x || coord.s >= uCrop[i].y) alpha = 0.0;
	if (coord.t < uCrop[i].z || coord.t >= uCrop[i].w) alpha = 0.0;
	color *= alpha;
	return color;
}
'''

multiMixFrag['mainStart'] = '''vec4 mix, blend;
out vec4 fragColor;
void main()
{	
	int i = 0;
	vec2 texCoord = vUV.st;
'''

multiMixFrag['mainEnd'] = '''
	fragColor = mix;
}'''

multiMixFrag['mixBlend'] = ["texCoord = Coord(i); blend = COLOR; mix = BLEND_Index_; i ++;",
							"texCoord = Coord(i); blend = CROP; mix = BLEND_Index_; i++;"]


multiMixFrag['defineMode'] = "#define BLEND_Index_ _Mode_(mix, blend, uOpacity[i])"


multiMixFrag['blendModes'] =[
'''	
vec4 over(vec4 base, vec4 blend, float opacity){	
	vec4 baseA = base * (1-blend.a);	
	vec4 result = baseA + blend;
	return mix(base, result, opacity);
}
''','''
vec4 average(vec4 base, vec4 blend, float opacity){	
	//average
	vec4 result = (base + blend) * 0.5;
	return mix(base, result, opacity);
}
''','''
vec4 under(vec4 base, vec4 blend, float opacity){	
	// under
	vec4 result = (base.a == 0.0) ? blend : base;
	return mix(base, result, opacity);
}
''','''
vec4 cross(vec4 base, vec4 blend, float opacity){	
	//cross
	vec4 result;
	result = blend;	
	return mix(base, result, opacity);
}
''','''
vec4 darken(vec4 base, vec4 blend, float opacity){	
	//darken
	vec4 result = min(blend, base);
	return mix(base, result, opacity);
}
''','''
vec4 lighten(vec4 base, vec4 blend, float opacity){	
	//lighten
	vec4 result = max(blend, base);
	return mix(base, result, opacity);
}
''','''
vec4 multiply(vec4 base, vec4 blend, float opacity){	
	//multiply
	vec4 result = blend * base;
	return mix(base, result, opacity);
}
''','''
vec4 screen(vec4 base, vec4 blend, float opacity){	
	//screen
	vec4 result = WHITE - ((WHITE - blend) * (WHITE - base));
	return mix(base, result, opacity);
}
''','''
vec4 colorBurn(vec4 base, vec4 blend, float opacity){	
	//color burn
	vec4 result = WHITE - (WHITE - base) / blend;
	return mix(base, result, opacity);
}
''','''
vec4 colorDodge(vec4 base, vec4 blend, float opacity){	
	//color dodge
	vec4 result = base / (WHITE - blend);
	//return mix(base, result, opacity);
	return mix(base, vec4(result.rgb, blend.a), opacity);
}
''','''
vec4 overlay(vec4 base, vec4 blend, float opacity){	
	//overlay
	vec4 result;
	float luminance = dot(base, LUM_COEFF);
	if (luminance < 0.45)
		result = 2.0 * blend * base;
		else if (luminance > 0.55)
		result = WHITE - 2.0 * (WHITE - blend) * (WHITE - base);
	else
	{
		vec4 result1 = 2.0 * blend * base;
		vec4 result2 = WHITE - 2.0 * (WHITE - blend) * (WHITE - base);
		result = mix(result1, result2, (luminance - 0.45) * 10.0);
	}
	return mix(base, result, opacity);
}
''','''
vec4 softLight(vec4 base, vec4 blend, float opacity){	
	//soft light
	vec4 result = 2.0 * base * blend + base * base - 2.0 * base * base * blend;
	return mix(base, result, opacity);
}
''','''
vec4 hardLight(vec4 base, vec4 blend, float opacity){	
	//hard light
	vec4 result;
	float luminance = dot(blend, LUM_COEFF);
	if (luminance < 0.45)
		result = 2.0 * blend * base;
	else if (luminance > 0.55)
		result = WHITE - 2.0 * (WHITE - blend) * (WHITE - base);
	else
		{
			vec4 result1 = 2.0 * blend * base;
			vec4 result2 = WHITE - 2.0 * (WHITE - blend) * (WHITE - base);
			result = mix(result1, result2, (luminance - 0.45) * 10.0);
		}		
	return mix(base, result, opacity);
}
''','''
vec4 add(vec4 base, vec4 blend, float opacity){	
	//add
	vec4 result = blend + base;
	return mix(base, result, opacity);
}
''','''
vec4 subtract(vec4 base, vec4 blend, float opacity){	
	//subtract 
	vec4 result = blend - base;
	return mix(base, vec4(result.rgb, blend.a), opacity);
}
''','''
vec4 difference(vec4 base, vec4 blend, float opacity)
{	
	//difference
	vec4 result = abs(blend - base);
	return mix(base, vec4(result.rgb, blend.a), opacity);	
}
''','''
vec4 invDifference(vec4 base, vec4 blend, float opacity){	
	//inverse difference
	vec4 result = WHITE - abs(WHITE - base - blend);
	return mix(base, vec4(result.rgb, blend.a), opacity);
}
''','''
vec4 exclusion(vec4 base, vec4 blend, float opacity){	
	//exclusion
	vec4 result = base + blend - (2.0 * base * blend);
	return mix(base, vec4(result.rgb, blend.a), opacity);
}
''']

